save_path = fullfile('..', 'Dataset', 'precision_cm_results.mat');
save(save_path, ...
    'psi_x', 'psi_y', 'psi_x_est', 'psi_y_est', 'psi_x_relative_errors', 'psi_y_relative_errors', ...    
    'N_x_vector', 'N_y_vector', 'N_vector',                 ...
    'T_x_vector', 'T_y_vector', 'T_vector',                 ...
